11	.sb-hd{padding:10px 13px 8px;border-bottom:0.5px solid #ddd;flex-shrink:0}
12	.sb-title{font-size:13px;font-weight:500}
13	.sb-sub{font-size:10px;color:#888;margin-top:1px}
14	.sb-body{padding:9px 13px;flex:1;overflow-y:auto}
15	.sb-ft{padding:8px 13px;border-top:0.5px solid #ddd;display:flex;flex-direction:column;gap:4px;flex-shrink:0}
16	.sec{margin-bottom:10px}
17	.sec-h{font-size:10px;font-weight:500;color:#999;letter-spacing:0.07em;text-transform:uppercase;margin-bottom:5px;padding-bottom:3px;border-bottom:0.5px solid #eee}
