19	.sec-h.coral{color:#993C1D;border-color:#F5C4B3}
20	.sec-h.teal{color:#0F6E56;border-color:#9FE1CB}
21	.f{margin-bottom:5px}
22	.f label{display:block;font-size:11px;color:#666;margin-bottom:2px}
23	.f select,.f input[type=number]{width:100%;padding:4px 6px;border:0.5px solid #ccc;border-radius:6px;background:#f7f7f7;color:#222;font-size:11px}
