27	.rval{font-weight:500;color:#222}
28	.info-pill{display:inline-block;padding:2px 6px;border-radius:4px;font-size:10px;background:#f2f2f2;color:#666;border:0.5px solid #ddd;margin-top:2px}
29	.btn{padding:5px 10px;border:0.5px solid #ccc;border-radius:6px;background:#fff;color:#222;font-size:11px;cursor:pointer;width:100%}
30	.btn:hover{background:#f2f2f2}
31	.btn-p{background:#185FA5;color:#fff;border-color:#185FA5}
32	.btn-p:hover{background:#0C447C}
33	.main{flex:1;min-width:0;display:flex;flex-direction:column;background:#f5f5f3;height:800px}
34	.topbar{display:flex;align-items:center;gap:6px;padding:8px 12px;background:#fff;border-bottom:0.5px solid #ddd;flex-wrap:wrap;flex-shrink:0}
35	.topbar-t{font-size:13px;font-weight:500}
36	.badge{display:inline-flex;align-items:center;padding:2px 7px;border-radius:10px;font-size:10px;font-weight:500}
37	.b-bl{background:#E6F1FB;color:#0C447C}
38	.b-rd{background:#FCEBEB;color:#791F1F}
39	.b-gn{background:#EAF3DE;color:#27500A}
40	.b-am{background:#FAEEDA;color:#633806}
41	.sp{flex:1}
42	.tabs{display:flex;gap:2px}
43	.tab{padding:4px 10px;font-size:11px;cursor:pointer;border:0.5px solid transparent;border-radius:6px;color:#888}
44	.tab.on{background:#fff;border-color:#ccc;color:#222;font-weight:500}
45	.content{flex:1;padding:8px 12px;overflow-y:hidden;min-width:0;width:100%}
46	.mrow{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:5px;margin-bottom:5px}
