48	.mc-l{font-size:10px;color:#888;margin-bottom:2px}
49	.mc-v{font-size:15px;font-weight:500;line-height:1.1}
50	.mc-u{font-size:10px;color:#888;margin-left:1px}
51	.mc-s{font-size:10px;color:#aaa;margin-top:2px}
