75	.sb2{display:inline-block;padding:1px 5px;border-radius:9px;font-size:9px}
76	.s-e{background:#E6F1FB;color:#0C447C}.s-p{background:#FAEEDA;color:#633806}.s-l{background:#FCEBEB;color:#791F1F}
