80	.tip{display:inline-block;width:13px;height:13px;background:#e0e8f0;color:#185FA5;border-radius:50%;text-align:center;line-height:13px;font-size:9px;cursor:help;margin-left:2px;position:relative;vertical-align:middle;font-weight:700;flex-shrink:0}
81	.tip .tip-box{display:none;position:absolute;left:16px;top:-4px;z-index:9999;background:#222;color:#eee;font-size:10px;padding:7px 10px;border-radius:7px;width:220px;line-height:1.5;white-space:normal;font-weight:400;pointer-events:none;box-shadow:0 3px 10px rgba(0,0,0,.3)}
82	.tip:hover .tip-box{display:block}
83	.seg{display:flex;border:0.5px solid #ddd;border-radius:7px;overflow:hidden;margin-bottom:8px}
84	.seg button{flex:1;padding:5px 0;font-size:11px;border:none;background:#f7f7f7;color:#888;cursor:pointer;transition:background .15s}
85	.seg button.on{background:#185FA5;color:#fff}
86	.fa-row{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:5px;margin-bottom:7px}
