function drawGraphs(A,B,sf){
  const wc=A.failMode!=='ボルト破断',lc=wc?'#E24B4A':'#185FA5';
  const ds=[
    {label:'弾性域(A)',data:A.rows.filter(r=>!r.plastic&&!r.over).map(r=>({x:r.T,y:r.F*1000})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},
    {label:'塑性域(A)',data:A.rows.filter(r=>r.plastic&&!r.over).map(r=>({x:r.T,y:r.F*1000})),borderColor:'#EF9F27',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},
    {label:'限界域(A)',data:A.rows.filter(r=>r.over).map(r=>({x:r.T,y:r.F*1000})),borderColor:lc,backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,3],hidden:true}
  ];
  if(B){
    ds.push({label:'弾性域(B)',data:B.rows.filter(r=>!r.plastic&&!r.over).map(r=>({x:r.T,y:r.F*1000})),borderColor:'#D85A30',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2,borderDash:[4,2]});
    ds.push({label:'塑性域(B)',data:B.rows.filter(r=>r.plastic&&!r.over).map(r=>({x:r.T,y:r.F*1000})),borderColor:'#993C1D',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2,borderDash:[4,2]});
    const lcB=B.failMode!=='ボルト破断'?'#E24B4A':'#185FA5';
    ds.push({label:'限界域(B)',data:B.rows.filter(r=>r.over).map(r=>({x:r.T,y:r.F*1000})),borderColor:lcB,backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[2,2],hidden:true});
  }
  const lineLabels=[];
  if(A.T_lim){
    const rt=A.T_lim/sf,rf=(A.rows.find(r=>r.T>=rt)?.F||A.rows[A.rows.length-1].F)*1000*1.1;
    ds.push({label:'推奨トルク (A)',data:[{x:rt,y:0},{x:rt,y:rf}],borderColor:'#639922',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[3,3]});
    lineLabels.push({value:rt,label:`推奨トルク(A): ${rt.toFixed(1)} Nm`,color:'#639922',font:'bold 11px sans-serif'});
    const lf=(A.rows.find(r=>r.T>=A.T_lim)?.F||A.rows[A.rows.length-1].F)*1000*1.1;
    ds.push({label:'限界トルク (A)',data:[{x:A.T_lim,y:0},{x:A.T_lim,y:lf}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[5,5]});
    lineLabels.push({value:A.T_lim,label:`限界トルク(A): ${A.T_lim.toFixed(1)} Nm`,color:'#E24B4A',font:'bold 11px sans-serif'});
  }
  if(B&&B.T_lim){
    const rtB=B.T_lim/sf,rfB=Math.max((B.rows.find(r=>r.T>=rtB)?.F||B.rows[B.rows.length-1].F)*1000*1.1,(A.rows[A.rows.length-1]?.F||0)*1000*1.1);
    ds.push({label:'推奨トルク (B)',data:[{x:rtB,y:0},{x:rtB,y:rfB}],borderColor:'#8AB661',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[3,3]});
    lineLabels.push({value:rtB,label:`推奨トルク(B): ${rtB.toFixed(1)} Nm`,color:'#8AB661',font:'bold 11px sans-serif'});
    const lfB=Math.max((B.rows.find(r=>r.T>=B.T_lim)?.F||B.rows[B.rows.length-1].F)*1000*1.1,(A.rows[A.rows.length-1]?.F||0)*1000*1.1);
    ds.push({label:'限界トルク (B)',data:[{x:B.T_lim,y:0},{x:B.T_lim,y:lfB}],borderColor:'#FF6B4A',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[5,5]});
    lineLabels.push({value:B.T_lim,label:`限界トルク(B): ${B.T_lim.toFixed(1)} Nm`,color:'#FF6B4A',font:'bold 11px sans-serif'});
  }
  const opts={responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10,top:25,bottom:5}},plugins:{legend:{display:true,position:'top',align:'start',labels:{font:{size:10},padding:10,usePointStyle:true,boxWidth:8,boxHeight:8}},tooltip:{callbacks:{title:i=>`締付トルク T = ${parseFloat(i[0].raw.x).toFixed(1)} Nm`,label:i=>`${i.dataset.label}: F = ${parseFloat(i.raw.y).toFixed(0)} N`,afterLabel:function(ctx){const T=ctx.raw.x,F=ctx.raw.y;const sig=(F/A.b.As).toFixed(1),tau=(T*1000*(A.b.d3/2)/(Math.PI*Math.pow(A.b.d3/2,4)/2)*0.5).toFixed(1),seq=Math.sqrt(sig*sig+3*tau*tau).toFixed(1);return[`σ = ${sig} MPa (引張応力)`,`τ = ${tau} MPa (せん断応力)`,`σeq = ${seq} MPa (等価応力)`];}},backgroundColor:'rgba(0,0,0,0.85)',titleFont:{size:11,weight:'bold'},bodyFont:{size:10},padding:10},verticalLineLabels:{lines:lineLabels}},scales:{x:{type:'linear',beginAtZero:true,title:{display:true,text:'締め付けトルク T (Nm)',font:{size:10}},ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 F (N)',font:{size:10}},ticks:{font:{size:9},callback:v=>v.toFixed(0)},grace:'5%'}}};
  mkC('cTF',{type:'line',data:{datasets:ds},options:opts});
  ge('leg-tf').innerHTML='';
  const maxSeqRow=A.rows.reduce((max,r)=>r.seq>max.seq?r:max,A.rows[0]);
  const maxSeq=maxSeqRow.seq;

